import{_ as t,o as s,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Shadow Volume","description":"","frontmatter":{},"headers":[],"relativePath":"图形学/阴影.md","filePath":"图形学/阴影.md","lastUpdated":null}'),l={name:"图形学/阴影.md"};function i(n,e,r,u,m,p){return s(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="shadow-volume" tabindex="-1">Shadow Volume <a class="header-anchor" href="#shadow-volume" aria-label="Permalink to &quot;Shadow Volume&quot;">​</a></h1><p>基本原理是根据光源和遮蔽物的位置关系计算出场景中会产生阴影的区域（ shadow volume），然后对所有物体进行检测，以确定其会不会受阴影的影响。</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240723104052.png" alt="20240723104052"></p><p>图中的绿色物体就是所谓的遮蔽物，而灰色的区域就是 shadow volume。只有处于 shadow volume 里面的物体才会受阴影的影响。 <strong>如何确定一个物体是否处于Shadow volum之中？</strong></p><h2 id="z-pass算法" tabindex="-1">z-pass算法 <a class="header-anchor" href="#z-pass算法" aria-label="Permalink to &quot;z-pass算法&quot;">​</a></h2><p>z-pass算法是shadow-volume最开始的标准算法，用来确定某个像素是否处于阴影之中。</p><ul><li><strong>Pass1</strong>:开启深度写入，从相机视角渲场景深度，得到场景内所有物体的depth map.</li><li><strong>Pass2</strong>:关闭深度写入，打开模板写入，渲染所有的shadow volume（这里的shadow volume就是圆锥状的几何体），shadow volume的前面，z-test pass的话，stecil加一，z-test fail，stencil值不变。如果是背面，z-test通过stencil减一，否则不变。 <strong>这个操作的本质是，从视点向物体发出一条射线，当射线进入shadow volume时，stencil加一，离开时stencil减一。如果stencil为0，说明光进入和离开volume次数相等，表示物体不在shadow volume内。</strong></li></ul><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240723144434.png" alt="20240723144434"></p><ul><li><strong>Pass3</strong>: 完成第二步操作之后，根据每个像素的stencil值判断其是否处于阴影当中（如果 stencil 的值大于零，则这个像素在 shadow volume 内，否则在 shadow volume 的外面），然后据此绘制阴影效果。</li></ul><p><strong>算法缺点</strong> 上面的情景都是视点在shadow volume外面的情况，一旦视点进入到了shadow volume中，z-pass算法就立即失效了。</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240723145446.png" alt="20240723145446"></p><p>这副图里面的视线二进二出，按照 z-pass的算法，最后的 stencil 值为 0，表示物体在阴影外，可实际上物体是处于阴影内的。错误的原因就在于视点进入到阴影内，使得视线失去了一次进入 shadow volume的机会，让原本应该是 1 的 stencil 值变成了 0。</p><h2 id="z-fail算法" tabindex="-1">Z-Fail算法 <a class="header-anchor" href="#z-fail算法" aria-label="Permalink to &quot;Z-Fail算法&quot;">​</a></h2><ul><li><strong>Pass1</strong>:开启深度写入，渲染场景，跟z-pass一样</li><li><strong>Pass2</strong>:关闭深度写入，打开模板写入。渲染shadow volume，对于反面，如果z-test fail则stencil加一，否则不变。对于正面，如果z-test fail则stencil减一，否则不变。 <strong>深度测试失败的点意味着射线是往远平面投去，并且因为远平面往往设置在较远的位置，基本上 shadow volumes 是不会接近远平面的</strong></li></ul><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240723150006.png" alt="20240723150006"></p><p><strong>如何建立 shadow volume？</strong> 要正确的建立shadow volume，核心是找到silhouette edge。即光源看物体的轮廓线。Shadow volume 就是由silhouette edge 扩展到一定距离以外或者无穷远处得到的。</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240723154022.png" alt="20240723154022"></p><p>这副图是一个由 4 个三角形组成的多边形，假设光源处在读者头部的位置，那么外围的一圈实线就是所谓的 silhouette edge 。我们所要做的就是从原始数据里面将内部多余的 4 条边 ( 虚线 ) 去掉。具体实现步骤如下： 遍历模型的所有三角形</p><ul><li><p>计算 dot3( light_direction , triangle_normal ) 。用这个结果判断三角形是面向光源 (dot3&gt;0) 还是背向光源 (dot&lt;0) 。</p></li><li><p>对于面向光源的三角形，将所有的三条边压入一个 栈 ，和里面的边进行比较，如果发现重复的 (edge1 和 edge2) ，将这些边删除</p></li><li><p>检测过所有三角形的 所有边 以后， 栈 里面剩下的 边就是 当前光源 / 物体位置下面的 silhouette edge.</p></li><li><p>根据光源方向 , 利用 CPU 或者 vertex shader 将这些 silhouette edge 投射出去形成 shadow volume.</p></li></ul>',19)])])}const g=t(l,[["render",i]]);export{h as __pageData,g as default};
